/**
 * @astro-shad/forms -- shared server-side building blocks for form
 * endpoints: honeypot spam signal, HTML-escaping for email bodies, a
 * provider-agnostic mailer (Resend / Cloudflare Email Sending), and
 * captcha verification (Turnstile / reCAPTCHA) for bulk spam protection.
 * See docs/forms-and-submissions.md and docs/forms-email-providers.md.
 *
 * Every form endpoint (contact, newsletter, story submission, ...) owns its
 * own POST handler and field shape, but pulls its safety net from here --
 * one place to fix a security gap instead of one per endpoint.
 */
export * from './honeypot';
export * from './escape-html';
export * from './mailer';
export * from './captcha';

/**
 * mailer.ts -- @astro-shad/forms. One `Mailer` interface, two provider
 * factories (Resend HTTP API, Cloudflare's native Email Sending binding) --
 * see docs/forms-email-providers.md for full setup steps and when to pick
 * which. A form endpoint calls `mailer.send({...})` the same way regardless
 * of provider; swapping providers is swapping which factory built `mailer`,
 * not touching the call site:
 *
 *   const mailer = env.RESEND_API_KEY
 *     ? createResendMailer(env.RESEND_API_KEY)
 *     : createCloudflareMailer(env.EMAIL);
 *
 *   await mailer.send({
 *     to: ['team@example.com'],
 *     from: { email: 'contact@example.com', name: 'Website' },
 *     replyTo: submittedEmail,
 *     subject: 'New enquiry',
 *     html, text,
 *   });
 *
 * A third POST-based provider (Postmark, SendGrid, ...) is a third factory
 * returning the same `Mailer` shape -- nothing else in a form endpoint
 * needs to know it exists.
 */
export interface MailMessage {
  to: string[];
  from: { email: string; name?: string };
  replyTo?: string;
  subject: string;
  html: string;
  text?: string;
}

export interface Mailer {
  send(message: MailMessage): Promise<void>;
}

/** Resend (https://resend.com) -- plain HTTP API call, works on any runtime, not just Cloudflare. */
export function createResendMailer(apiKey: string): Mailer {
  return {
    async send(message) {
      const res = await fetch('https://api.resend.com/emails', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${apiKey}`,
          'content-type': 'application/json',
        },
        body: JSON.stringify({
          from: message.from.name ? `${message.from.name} <${message.from.email}>` : message.from.email,
          to: message.to,
          reply_to: message.replyTo,
          subject: message.subject,
          html: message.html,
          text: message.text,
        }),
      });
      if (!res.ok) {
        const body = (await res.json().catch(() => ({}))) as { message?: string };
        throw new Error(`Resend send failed (${res.status}): ${body.message ?? res.statusText}`);
      }
    },
  };
}

/** Minimal shape of Cloudflare's native `send_email` binding -- see wrangler's generated types for the full SendEmail interface. */
interface CloudflareSendEmailBinding {
  send(message: MailMessage): Promise<{ messageId?: string }>;
}

/** Cloudflare Email Sending binding -- no third-party account, Worker-identity-authenticated, Cloudflare-only. */
export function createCloudflareMailer(binding: CloudflareSendEmailBinding): Mailer {
  return {
    async send(message) {
      await binding.send(message);
    },
  };
}

/**
 * captcha.ts -- @astro-shad/forms. Bulk/bot spam protection: verifies a
 * client-submitted challenge token server-side before the form is treated
 * as legitimate. Unlike the honeypot (a passive signal with no setup), this
 * requires a widget on the form and a site/secret keypair from whichever
 * provider you pick -- see docs/forms-email-providers.md for the two
 * documented options and their setup steps.
 *
 * Both Cloudflare Turnstile and Google reCAPTCHA (v2/v3) expose the same
 * shape of server-side check: POST { secret, response (the token), remoteip }
 * to a siteverify endpoint, get back { success, ... }. One shared
 * implementation, two one-line wrappers -- swapping provider (or adding a
 * third that follows the same siteverify convention) is picking which
 * wrapper you call, not rewriting the check.
 *
 *   const { success } = await verifyTurnstile(token, env.TURNSTILE_SECRET_KEY);
 *   if (!success) return json({ ok: false, error: 'Captcha failed.' }, 400);
 */
export interface CaptchaVerifyResult {
  success: boolean;
  /** reCAPTCHA v3 only -- 0.0 (likely bot) to 1.0 (likely human) */
  score?: number;
  errorCodes?: string[];
}

async function verifyCaptchaToken(
  endpoint: string,
  secret: string,
  token: string,
  remoteIp?: string
): Promise<CaptchaVerifyResult> {
  const body = new URLSearchParams({ secret, response: token });
  if (remoteIp) body.set('remoteip', remoteIp);

  const res = await fetch(endpoint, {
    method: 'POST',
    headers: { 'content-type': 'application/x-www-form-urlencoded' },
    body,
  });
  const json = (await res.json()) as { success: boolean; score?: number; 'error-codes'?: string[] };

  return { success: json.success, score: json.score, errorCodes: json['error-codes'] };
}

/** Cloudflare Turnstile -- widget: https://challenges.cloudflare.com/turnstile/v0/api.js */
export function verifyTurnstile(token: string, secret: string, remoteIp?: string) {
  return verifyCaptchaToken('https://challenges.cloudflare.com/turnstile/v0/siteverify', secret, token, remoteIp);
}

/** Google reCAPTCHA (v2 checkbox or v3 score-based) -- widget: https://www.google.com/recaptcha/api.js */
export function verifyRecaptcha(token: string, secret: string, remoteIp?: string) {
  return verifyCaptchaToken('https://www.google.com/recaptcha/api/siteverify', secret, token, remoteIp);
}
